// =============================================================================
// uart_focdemo — Full-Duplex UART Transceiver (8N1)
// Generated by ice40-codegen peripheral system
//
// Baud rate:      115200
// Clock freq:     48000000
// Baud divider:   417 (9-bit counter)
// Oversampling:   16x (RX samples at sub-tick 417 / 16)
// Format:         8N1 — start(0), D0..D7 LSB-first, stop(1)
// =============================================================================
`default_nettype none

module uart_focdemo (
    input  wire       clk,
    input  wire       rst_n,

    // --- TX interface ---
    input  wire [7:0] tx_data,
    input  wire       tx_valid,
    output wire       tx_ready,

    // --- RX interface ---
    output wire [7:0] rx_data,
    output wire       rx_valid,

    // --- Physical pins ---
    output wire       tx,
    input  wire       rx
);

    // =========================================================================
    // Baud-rate parameters
    // =========================================================================
    // Full-bit period in clock ticks.
    localparam BAUD_DIV     = 417;
    // RX oversampling: 16 samples per bit.  Each sample tick = BAUD_DIV / 16.
    // Integer truncation is intentional; residual error is < 1 clock.
    localparam OVS_DIV      = BAUD_DIV / 16;

    // =========================================================================
    // TX State Machine
    // =========================================================================
    //  IDLE  : tx=1, waiting for tx_valid
    //  START : send start bit (0) for one full baud period
    //  DATA  : send D0..D7, one bit per baud period
    //  STOP  : send stop bit (1) for one full baud period, pulse tx_ready
    // =========================================================================
    localparam TX_IDLE  = 2'd0;
    localparam TX_START = 2'd1;
    localparam TX_DATA  = 2'd2;
    localparam TX_STOP  = 2'd3;

    reg [1:0]                    tx_state;
    reg [8:0] tx_baud_cnt;  // counts down from BAUD_DIV-1
    reg [2:0]                    tx_bit_idx;   // 0..7
    reg [7:0]                    tx_shift;     // holds the byte being sent
    reg                          tx_reg;       // current TX line level
    reg                          tx_ready_reg;

    assign tx       = tx_reg;
    assign tx_ready = tx_ready_reg;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            tx_state     <= TX_IDLE;
            tx_baud_cnt  <= {9{1'b0}};
            tx_bit_idx   <= 3'd0;
            tx_shift     <= 8'd0;
            tx_reg       <= 1'b1;   // idle-high
            tx_ready_reg <= 1'b1;
        end else begin
            case (tx_state)
                // ---------------------------------------------------------
                // IDLE: line stays high; accept a new byte when tx_valid
                // ---------------------------------------------------------
                TX_IDLE: begin
                    tx_reg       <= 1'b1;
                    tx_ready_reg <= 1'b1;
                    if (tx_valid) begin
                        tx_shift    <= tx_data;
                        tx_baud_cnt <= BAUD_DIV[8:0] - 1'b1;
                        tx_reg      <= 1'b0;   // start bit
                        tx_ready_reg <= 1'b0;
                        tx_state    <= TX_START;
                    end
                end

                // ---------------------------------------------------------
                // START: hold start bit for one full baud period
                // ---------------------------------------------------------
                TX_START: begin
                    if (tx_baud_cnt == {9{1'b0}}) begin
                        // Start bit done — send D0 first (LSB first)
                        tx_reg      <= tx_shift[0];
                        tx_shift    <= {1'b0, tx_shift[7:1]};  // right-shift for LSB-first
                        tx_bit_idx  <= 3'd0;                   // D0 sent; 7 more to go
                        tx_baud_cnt <= BAUD_DIV[8:0] - 1'b1;
                        tx_state    <= TX_DATA;
                    end else begin
                        tx_baud_cnt <= tx_baud_cnt - 1'b1;
                    end
                end

                // ---------------------------------------------------------
                // DATA: shift out D0..D7, LSB first
                // ---------------------------------------------------------
                TX_DATA: begin
                    if (tx_baud_cnt == {9{1'b0}}) begin
                        if (tx_bit_idx == 3'd7) begin
                            // All 8 data bits done — move to STOP
                            tx_reg      <= 1'b1;   // stop bit
                            tx_baud_cnt <= BAUD_DIV[8:0] - 1'b1;
                            tx_state    <= TX_STOP;
                        end else begin
                            tx_reg      <= tx_shift[0];
                            tx_shift    <= {1'b0, tx_shift[7:1]};
                            tx_bit_idx  <= tx_bit_idx + 1'b1;
                            tx_baud_cnt <= BAUD_DIV[8:0] - 1'b1;
                        end
                    end else begin
                        tx_baud_cnt <= tx_baud_cnt - 1'b1;
                    end
                end

                // ---------------------------------------------------------
                // STOP: hold stop bit for one baud period, then go idle
                // ---------------------------------------------------------
                TX_STOP: begin
                    if (tx_baud_cnt == {9{1'b0}}) begin
                        tx_ready_reg <= 1'b1;
                        tx_state     <= TX_IDLE;
                        // If another byte is already waiting, accept it immediately
                        if (tx_valid) begin
                            tx_shift    <= tx_data;
                            tx_baud_cnt <= BAUD_DIV[8:0] - 1'b1;
                            tx_reg      <= 1'b0;
                            tx_ready_reg <= 1'b0;
                            tx_state    <= TX_START;
                        end
                    end else begin
                        tx_baud_cnt <= tx_baud_cnt - 1'b1;
                    end
                end

                default: tx_state <= TX_IDLE;
            endcase
        end
    end

    // =========================================================================
    // RX State Machine — 16x oversampling
    // =========================================================================
    //  Each OVS_DIV clocks = 1 sample tick.  16 sample ticks = 1 baud period.
    //
    //  IDLE    : waiting for falling edge on rx (start of start bit)
    //  START   : verify start bit at sample tick 8 (mid-bit); abort if high
    //  DATA    : collect three majority-vote samples (ticks 6/7/8 of each bit)
    //  STOP    : verify stop bit at tick 8, pulse rx_valid
    // =========================================================================
    localparam RX_IDLE  = 2'd0;
    localparam RX_START = 2'd1;
    localparam RX_DATA  = 2'd2;
    localparam RX_STOP  = 2'd3;

    // RX input synchroniser (2-FF CDC)
    reg rx_meta, rx_sync, rx_prev;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            rx_meta <= 1'b1;
            rx_sync <= 1'b1;
            rx_prev <= 1'b1;
        end else begin
            rx_meta <= rx;
            rx_sync <= rx_meta;
            rx_prev <= rx_sync;
        end
    end

    // Oversampling counter and sample-tick pulse (declarations only)
    reg [8:0] rx_ovs_cnt;   // counts down from OVS_DIV-1
    reg       rx_sample_tick; // one-clock pulse every OVS_DIV clocks

    // Main RX FSM (includes oversampling counter to avoid multi-driver)
    reg [1:0]  rx_state;
    reg [3:0]  rx_tick_cnt;   // 0..15 within the current baud period
    reg [2:0]  rx_bit_idx;    // 0..7 data bits received
    reg [7:0]  rx_shift;      // accumulates received bits (LSB first)
    reg [7:0]  rx_data_reg;
    reg        rx_valid_reg;

    // Majority vote accumulator for the three centre samples (ticks 6, 7, 8)
    reg [1:0]  rx_vote_acc;   // counts '1' samples; majority if >= 2

    assign rx_data  = rx_data_reg;
    assign rx_valid = rx_valid_reg;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            rx_ovs_cnt     <= {9{1'b0}};
            rx_sample_tick <= 1'b0;
            rx_state       <= RX_IDLE;
            rx_tick_cnt    <= 4'd0;
            rx_bit_idx     <= 3'd0;
            rx_shift       <= 8'd0;
            rx_data_reg    <= 8'd0;
            rx_valid_reg   <= 1'b0;
            rx_vote_acc    <= 2'd0;
        end else begin
            // Default: clear one-clock pulses
            rx_valid_reg   <= 1'b0;
            rx_sample_tick <= 1'b0;

            // --- Oversampling counter (free-running, reset on start-bit edge) ---
            if (rx_ovs_cnt == {9{1'b0}}) begin
                rx_ovs_cnt     <= OVS_DIV[8:0] - 1'b1;
                rx_sample_tick <= 1'b1;
            end else begin
                rx_ovs_cnt <= rx_ovs_cnt - 1'b1;
            end

            // --- RX state machine ---
            case (rx_state)
                // ---------------------------------------------------------
                // IDLE: watch for falling edge on rx_sync (start bit)
                // When detected, reset OVS counter to align sampling
                // ---------------------------------------------------------
                RX_IDLE: begin
                    if (rx_prev == 1'b1 && rx_sync == 1'b0) begin
                        rx_ovs_cnt     <= OVS_DIV[8:0] - 1'b1;
                        rx_sample_tick <= 1'b0;
                        rx_tick_cnt    <= 4'd0;
                        rx_vote_acc    <= 2'd0;
                        rx_state       <= RX_START;
                    end
                end

                // ---------------------------------------------------------
                // START: verify start bit at mid-bit (tick 7) for glitch
                // rejection, then wait until tick 15 (end of start bit)
                // so RX_DATA windows align with actual data-bit boundaries.
                // ---------------------------------------------------------
                RX_START: begin
                    if (rx_sample_tick) begin
                        rx_tick_cnt <= rx_tick_cnt + 1'b1;
                        if (rx_tick_cnt == 4'd7) begin
                            // Mid-start-bit glitch check
                            if (rx_sync == 1'b1) begin
                                rx_state <= RX_IDLE;
                            end
                        end else if (rx_tick_cnt == 4'd15) begin
                            // Full start bit consumed — enter DATA aligned
                            rx_bit_idx  <= 3'd0;
                            rx_shift    <= 8'd0;
                            rx_vote_acc <= 2'd0;
                            rx_tick_cnt <= 4'd0;
                            rx_state    <= RX_DATA;
                        end
                    end
                end

                // ---------------------------------------------------------
                // DATA: collect 8 data bits, LSB first
                // Majority vote on sample ticks 6, 7, 8 (centre triplet)
                // Latch at tick 15 (full baud period per bit)
                // ---------------------------------------------------------
                RX_DATA: begin
                    if (rx_sample_tick) begin
                        rx_tick_cnt <= rx_tick_cnt + 1'b1;

                        if (rx_tick_cnt == 4'd6 || rx_tick_cnt == 4'd7 || rx_tick_cnt == 4'd8) begin
                            rx_vote_acc <= rx_vote_acc + {1'b0, rx_sync};
                        end

                        if (rx_tick_cnt == 4'd15) begin
                            rx_shift    <= {(rx_vote_acc >= 2'd2 ? 1'b1 : 1'b0), rx_shift[7:1]};
                            rx_vote_acc <= 2'd0;
                            rx_tick_cnt <= 4'd0;

                            if (rx_bit_idx == 3'd7) begin
                                rx_state <= RX_STOP;
                            end else begin
                                rx_bit_idx <= rx_bit_idx + 1'b1;
                            end
                        end
                    end
                end

                // ---------------------------------------------------------
                // STOP: sample at mid-bit of stop bit; pulse rx_valid if high
                // ---------------------------------------------------------
                RX_STOP: begin
                    if (rx_sample_tick) begin
                        rx_tick_cnt <= rx_tick_cnt + 1'b1;
                        if (rx_tick_cnt == 4'd8) begin
                            if (rx_sync == 1'b1) begin
                                rx_data_reg  <= rx_shift;
                                rx_valid_reg <= 1'b1;
                            end
                            rx_state    <= RX_IDLE;
                            rx_tick_cnt <= 4'd0;
                        end
                    end
                end

                default: rx_state <= RX_IDLE;
            endcase
        end
    end

endmodule
